-- Program: Karate Conditioning
-- Category: Martial Arts -> martial_arts
-- Priority: Med
-- Durations: [4, 8, 12], Sessions: [4, 5]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Karate Conditioning',
    'Karate-inspired conditioning with punching drills, kicks, stances, and full-body functional strength',
    'martial_arts',
    'all_levels',
    12,
    5,
    'full_body',
    ARRAY['Increase maximal strength', 'Progressive overload', 'Build cardiovascular endurance', 'Improve VO2 max']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Karate Conditioning - 4w 4x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Karate Conditioning - 4w 4x/wk',
    'martial_arts',
    4,
    60,
    ARRAY['Increase maximal strength', 'Progressive overload', 'Build cardiovascular endurance', 'Improve VO2 max']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Karate Conditioning'
ON CONFLICT DO NOTHING;

